"""Book module - Core Book class with encapsulation."""class Book:    """    Represents a book in the library collection.    Attributes:        title (str): Book title        author (str): Book author        isbn (str): Unique ISBN identifier        publication_year (int): Year of publication        is_reference (bool): If True, cannot be borrowed (or shorter loan)    """    def __init__(self, title, author, isbn, publication_year, is_reference=False):        self.title = title        self.author = author        self.isbn = isbn        self.publication_year = publication_year        self.is_reference = is_reference        # Private attributes (encapsulated state)        self._is_checked_out = False    def check_out(self):        """Mark the book as checked out.        Returns:            bool: True if successful, False if already checked out.        """        if self._is_checked_out:            return False        self._is_checked_out = True        return True    def check_in(self):        """Mark the book as returned.        Returns:            bool: True if successful, False if not checked out.        """        if not self._is_checked_out:            return False        self._is_checked_out = False        return True    def is_available(self):        """Check if the book is available for borrowing."""        return not self._is_checked_out    def get_display_info(self):        """Return a formatted string with book details."""        status = "Available" if self.is_available() else "Checked Out"        info = f"'{self.title}' by {self.author} ({self.publication_year})\n"        info += f"  ISBN: {self.isbn} | Status: {status}"        if self.is_reference:            info += " | Reference Only"        return info